mapper.select:
select avg(lp.progress_percent)
from learning_progress lp
join course_resource cr on cr.id = lp.resource_id
where cr.course_id = #{courseId}
  and cr.status = 1
  and lp.user_id = #{studentId}

select max(lp.last_viewed_at)
from learning_progress lp
join course_resource cr on cr.id = lp.resource_id
where cr.course_id = #{courseId}
  and cr.status = 1
  and lp.user_id = #{studentId}
